package github.chains;

import spoon.Launcher;
import spoon.reflect.code.CtExpression;
import spoon.reflect.code.CtInvocation;
import spoon.reflect.declaration.CtAnnotation;
import spoon.reflect.declaration.CtClass;
import spoon.reflect.declaration.CtElement;
import spoon.reflect.declaration.CtImport;
import spoon.reflect.declaration.CtType;
import spoon.reflect.factory.Factory;
import spoon.reflect.reference.CtExecutableReference;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.filter.TypeFilter;

import java.io.File;
import java.util.List;

public class Main {
    public static void main(String[] args) {
        // Configuration parameters - these can be changed for different projects
        String sourceDirectory = args.length > 0 ? args[0] : "/workspace/cdi-test";
        String oldPackage = "javax.annotation";
        String newPackage = "jakarta.annotation";

        Launcher launcher = new Launcher();
        launcher.addInputResource(sourceDirectory);
        launcher.setSourceOutputDirectory(sourceDirectory + "/src-gen");
        launcher.getEnvironment().setAutoImports(true);
        launcher.getEnvironment().setComplianceLevel(11);

        // Process the code
        launcher.buildModel();
        Factory factory = launcher.getFactory();

        // Replace imports
        List<CtImport> imports = factory.getModel().getElements(new TypeFilter<>(CtImport.class));
        for (CtImport imp : imports) {
            if (imp.getReference() != null && imp.getReference().getQualifiedName().startsWith(oldPackage)) {
                // Update import to use jakarta.annotation
                imp.setReference(factory.createImport(
                    factory.Type().createReference(newPackage + "." + imp.getReference().getSimpleName())
                ));
            }
        }

        // Replace all annotations from javax.annotation to jakarta.annotation
        List<CtAnnotation<?>> annotations = factory.getModel().getElements(new TypeFilter<>(CtAnnotation.class));
        for (CtAnnotation<?> annotation : annotations) {
            CtTypeReference<?> annotationType = annotation.getAnnotationType();
            if (annotationType != null && annotationType.getQualifiedName().startsWith(oldPackage)) {
                // Create new annotation type reference with jakarta.annotation
                String newAnnotationName = newPackage + "." + annotationType.getSimpleName();
                annotation.setAnnotationType(
                    factory.Type().createReference(newAnnotationName)
                );
            }
        }

        // Generate the modified code
        launcher.writeProcessedSourceFiles();
        System.out.println("Transformation complete. Generated code in " + sourceDirectory + "/src-gen");
    }
}

