find "$SOURCE_DIR" -name "*.java" -exec sed -i "s/import $JAVAX_JPA\./import $JAKARTA_JPA\./g" {} \;
find "$SOURCE_DIR" -name "*.java" -exec sed -i "s/@$JAVAX_JPA\./@$JAKARTA_JPA\./g" {} \;

echo "Fixing JSF imports..."
