find "$SOURCE_DIR" -name "*.java" -exec sed -i "s/import $JAVAX_EJB\./import $JAKARTA_EJB\./g" {} \;
find "$SOURCE_DIR" -name "*.java" -exec sed -i "s/@$JAVAX_EJB\./@$JAKARTA_EJB\./g" {} \;

