find "$SOURCE_DIR" -name "*.java" -exec sed -i "s/@$JAVAX_JTA\./@$JAKARTA_JTA\./g" {} \;

echo "Migration complete!"

# Verify the changes
find "$SOURCE_DIR" -name "*.java" -exec grep -l "import javax" {} \; | while read file; do
    echo "Warning: Still has javax imports in $file"
